tool_calls:
awk '
NR == FNR {
    # Read products.csv (first file)
    if (NR > 1) {  # Skip header
        split($0, arr, ",")
        product_id = arr[1]
        category = arr[3]
        price = arr[4]
        products[product_id] = category "," price
    }
    next
}
NR > 1 {
    # Read orders.csv (second file) and join with products
    split($0, arr, ",")
    order_id = arr[1]
    product_id = arr[2]
    quantity = arr[3]

    if (product_id in products) {
        split(products[product_id], info, ",")
        category = info[1]
        price = info[2]
        revenue = quantity * price
        category_revenue[category] += revenue
    }
}
END {
    # Sort and print results
    for (cat in category_revenue) {
        print cat, category_revenue[cat]
    }
}
' /data/products.csv /data/orders.csv | sort -k2 -nr | awk '{print $1": "$2}'

